content.content:
  1→/**
  2→ * SKF Installer - Core orchestrator
  3→ * Copies SKF source files, compiles agents, creates folder structure.
  4→ */
  5→
  6→const path = require('node:path');
  7→const fs = require('fs-extra');
  8→const { spinner } = require('@clack/prompts');
  9→const yaml = require('js-yaml');
 10→const { compileAgentFile } = require('./compiler');
 11→const { generateIdeCommands } = require('./ide-commands');
 12→const { writeManifest } = require('./manifest');
 13→
 14→class Installer {
 15→  constructor() {
 16→    // Resolve directories relative to this file (tools/cli/lib/ -> up 3 levels)
 17→    const repoRoot = path.resolve(__dirname, '..', '..', '..');
 18→    this.srcDir = path.join(repoRoot, 'src');
 19→    this.docsDir = path.join(repoRoot, 'docs');
 20→  }
 21→
 22→  async install(config) {
 23→    const { projectDir, skfFolder } = config;
 24→    const skfDir = path.join(projectDir, skfFolder);
 25→    const action = config._action || 'fresh';
 26→    const s = spinner();
 27→
 28→    // Handle update vs fresh for existing installation
 29→    if (action === 'update' && (await fs.pathExists(skfDir))) {
 30→      const configPath = path.join(skfDir, 'config.yaml');
 31→      if (!config._savedConfigYaml && (await fs.pathExists(configPath))) {
 32→        config._savedConfigYaml = await fs.readFile(configPath, 'utf8');
 33→      }
 34→
 35→      // On update, extract settings from saved config
 36→      if (config._savedConfigYaml) {
 37→        try {
 38→          const savedData = yaml.load(config._savedConfigYaml);
 39→          if (!config.ides && savedData.ides) config.ides = savedData.ides;
 40→          if (!config.skills_output_folder && savedData.skills_output_folder) config.skills_output_folder = savedData.skills_output_folder;
 41→          if (!config.forge_data_folder && savedData.forge_data_folder) config.forge_data_folder = savedData.forge_data_folder;
 42→        } catch {
 43→          /* ignore parse errors, defaults will apply */
 44→        }
 45→      }
 46→
 47→      s.start('Updating SKF files...');
 48→      await fs.remove(skfDir);
 49→      s.stop('Old files cleared');
 50→    } else if (action === 'fresh' && (await fs.pathExists(skfDir))) {
 51→      s.start('Removing existing SKF installation...');
 52→      await fs.remove(skfDir);
 53→      s.stop('Old installation removed');
 54→    }
 55→
 56→    // Ensure parent directory exists (for _bmad/skf/)
 57→    await fs.ensureDir(path.dirname(skfDir));
 58→
 59→    // Step 1: Copy source files
 60→    s.start('Copying SKF files...');
 61→    try {
 62→      await this.copySrcFiles(skfDir);
 63→      s.stop('SKF files copied');
 64→    } catch (error) {
 65→      s.stop('Failed to copy SKF files');
 66→      throw error;
 67→    }
 68→
 69→    // Step 2: Setup agent sidecar
 70→    s.start('Setting up agent sidecar...');
 71→    try {
 72→      await this.setupSidecar(projectDir);
 73→      s.stop('Agent sidecar initialized');
 74→    } catch (error) {
 75→      s.stop('Failed to setup sidecar');
 76→      throw error;
 77→    }
 78→
 79→    // Step 2b: Update .gitignore
 80→    await this.updateGitignore(projectDir);
 81→
 82→    // Step 3: Write config.yaml
 83→    s.start('Writing configuration...');
 84→    try {
 85→      await this.writeConfig(skfDir, config);
 86→      s.stop('Configuration saved');
 87→    } catch (error) {
 88→      s.stop('Failed to write configuration');
 89→      throw error;
 90→    }
 91→
 92→    // Step 4: Compile agents
 93→    s.start('Compiling agents...');
 94→    try {
 95→      const agents = await this.compileAgents(skfDir, skfFolder);
 96→      s.stop(`Compiled ${agents.length} agent${agents.length === 1 ? '' : 's'}`);
 97→    } catch (error) {
 98→      s.stop('Failed to compile agents');
 99→      throw error;
100→    }
101→
102→    // Step 5: Create output folders
103→    s.start('Creating project folders...');
104→    try {
105→      await this.createOutputFolders(projectDir, config);
106→      s.stop('Project folders created');
107→    } catch (error) {
108→      s.stop('Failed to create project folders');
109→      throw error;
110→    }
111→
112→    // Step 6: Copy learning material (optional)
113→    if (config.install_learning !== false) {
114→      s.start('Copying learning & reference material...');
115→      try {
116→        await this.copyLearningMaterial(projectDir);
117→        s.stop('Learning material added to _skf-learn/');
118→      } catch (error) {
119→        s.stop('Failed to copy learning material');
120→        throw error;
121→      }
122→    }
123→
124→    // Step 7: Generate IDE command files
125→    let ideFiles = [];
126→    const selectedIdes = config.ides || [];
127→    if (selectedIdes.length > 0 && !selectedIdes.every((ide) => ide === 'other')) {
128→      s.start('Generating IDE commands...');
129→      try {
130→        const ideResult = await generateIdeCommands(projectDir, skfFolder, selectedIdes);
131→        ideFiles = ideResult.files || [];
132→        if (ideResult.generated > 0) {
133→          s.stop(`IDE commands generated for ${ideResult.ides.join(', ')}`);
134→        } else {
135→          s.stop('No IDE commands to generate');
136→        }
137→      } catch (error) {
138→        s.stop('Failed to generate IDE commands');
139→        throw error;
140→      }
141→    }
142→
143→    // Step 8: Write installation manifest
144→    s.start('Writing manifest...');
145→    try {
146→      const packageJson = require('../../../package.json');
147→      await writeManifest(projectDir, config, {
148→        version: packageJson.version,
149→        ideFiles,
150→      });
151→      s.stop('Installation manifest saved');
152→    } catch (error) {
153→      s.stop('Failed to write manifest');
154→      throw error;
155→    }
156→
157→    return { success: true, skfDir, projectDir };
158→  }
159→
160→  /**
161→   * Copy src/ content into the target SKF directory.
162→   * Workflows are placed under a skillforge/ subdirectory to match agent path references.
163→   */
164→  async copySrcFiles(skfDir) {
165→    // Copy agents and knowledge directly
166→    for (const dir of ['agents', 'knowledge']) {
167→      const src = path.join(this.srcDir, dir);
168→      const dest = path.join(skfDir, dir);
169→      if (await fs.pathExists(src)) {
170→        await fs.copy(src, dest);
171→      }
172→    }
173→
174→    // Workflows go under workflows/skillforge/ to match agent YAML paths
175→    const workflowsSrc = path.join(this.srcDir, 'workflows');
176→    const workflowsDest = path.join(skfDir, 'workflows', 'skillforge');
177→    if (await fs.pathExists(workflowsSrc)) {
178→      await fs.copy(workflowsSrc, workflowsDest);
179→    }
180→
181→    // Copy module.yaml and module-help.csv
182→    for (const file of ['module.yaml', 'module-help.csv']) {
183→      const src = path.join(this.srcDir, file);
184→      if (await fs.pathExists(src)) {
185→        await fs.copy(src, path.join(skfDir, file));
186→      }
187→    }
188→  }
189→
190→  /**
191→   * Setup the ferris sidecar directory with template files.
192→   * Existing sidecar files are preserved (they contain user state).
193→   */
194→  async setupSidecar(projectDir) {
195→    const sidecarDir = path.join(projectDir, '_bmad', '_memory', 'forger-sidecar');
196→    await fs.ensureDir(sidecarDir);
197→
198→    const forgerSrc = path.join(this.srcDir, 'forger');
199→    if (await fs.pathExists(forgerSrc)) {
200→      const files = await fs.readdir(forgerSrc);
201→      for (const file of files) {
202→        if (file.endsWith('.yaml') || file.endsWith('.yml')) {
203→          const dest = path.join(sidecarDir, file);
204→          // Don't overwrite existing sidecar files (preserves user state)
205→          if (!(await fs.pathExists(dest))) {
206→            await fs.copy(path.join(forgerSrc, file), dest);
207→          }
208→        }
209→      }
210→    }
211→  }
212→
213→  async writeConfig(skfDir, config) {
214→    // On update, restore the user's existing config
215→    if (config._savedConfigYaml) {
216→      await fs.writeFile(path.join(skfDir, 'config.yaml'), config._savedConfigYaml, 'utf8');
217→      return;
218→    }
219→
220→    // Get user name from git or system
221→    const getUserName = () => {
222→      try {
223→        const { execSync } = require('node:child_process');
224→        return execSync('git config user.name', { encoding: 'utf8' }).trim() || 'Developer';
225→      } catch {
226→        return 'Developer';
227→      }
228→    };
229→
230→    const configData = {
231→      user_name: getUserName(),
232→      project_name: config.project_name || 'Untitled Project',
233→      communication_language: 'en',
234→      document_output_language: 'en',
235→      skills_output_folder: config.skills_output_folder || 'skills',
236→      forge_data_folder: config.forge_data_folder || 'forge-data',
237→      skf_folder: config.skfFolder,
238→      ides: config.ides || [],
239→    };
240→
241→    const yamlStr = yaml.dump(configData, { lineWidth: -1 });
242→    await fs.writeFile(path.join(skfDir, 'config.yaml'), `# SKF Configuration - Generated by installer\n${yamlStr}`, 'utf8');
243→  }
244→
245→  async compileAgents(skfDir, skfFolder) {
246→    const agentsDir = path.join(skfDir, 'agents');
247→    const files = await fs.readdir(agentsDir);
248→    const agentFiles = files.filter((f) => f.endsWith('.agent.yaml'));
249→    const results = [];
250→
251→    for (const file of agentFiles) {
252→      const yamlPath = path.join(agentsDir, file);
253→      const result = compileAgentFile(yamlPath, { skfFolder });
254→      results.push(result);
255→    }
256→
257→    return results;
258→  }
259→
260→  async createOutputFolders(projectDir, config) {
261→    const skillsFolder = config.skills_output_folder || 'skills';
262→    const forgeDataFolder = config.forge_data_folder || 'forge-data';
263→
264→    for (const folder of [skillsFolder, forgeDataFolder]) {
265→      const folderPath = path.join(projectDir, folder);
266→      if (!(await fs.pathExists(folderPath))) {
267→        await fs.ensureDir(folderPath);
268→        await fs.writeFile(path.join(folderPath, '.gitkeep'), '# This file ensures the directory is tracked by git\n');
269→      }
270→    }
271→  }
272→
273→  async updateGitignore(projectDir) {
274→    const gitignorePath = path.join(projectDir, '.gitignore');
275→    const entry = '_bmad/_memory/';
276→
277→    try {
278→      if (await fs.pathExists(gitignorePath)) {
279→        const content = await fs.readFile(gitignorePath, 'utf8');
280→        // Check if entry already present (exact line match)
281→        const lines = content.split('\n');
282→        if (lines.some((line) => line.trim() === entry)) return;
283→        // Append with preceding newline if file doesn't end with one
284→        const prefix = content.endsWith('\n') ? '' : '\n';
285→        await fs.appendFile(gitignorePath, `${prefix}${entry}\n`, 'utf8');
286→      } else {
287→        await fs.writeFile(gitignorePath, `${entry}\n`, 'utf8');
288→      }
289→    } catch {
290→      // Non-critical — don't fail the install over .gitignore
291→    }
292→  }
293→
294→  async copyLearningMaterial(projectDir) {
295→    const learnDir = path.join(projectDir, '_skf-learn');
296→    if (await fs.pathExists(this.docsDir)) {
297→      await fs.copy(this.docsDir, learnDir, {
298→        filter: (srcPath) => {
299→          // Skip website-specific files
300→          return !path.basename(srcPath).startsWith('404');
301→        },
302→      });
303→    }
304→  }
305→}
306→
307→module.exports = { Installer };
308→

  1→/**
  2→ * SKF Manifest - Tracks installed files for uninstall and smart updates.
  3→ * Writes _bmad/_config/manifest.yaml after each install.
  4→ */
  5→
  6→const path = require('node:path');
  7→const fs = require('fs-extra');
  8→const yaml = require('js-yaml');
  9→
 10→const MANIFEST_DIR = '_bmad/_config';
 11→const MANIFEST_FILE = 'skf-manifest.yaml';
 12→
 13→/**
 14→ * Recursively collect all file paths under a directory,
 15→ * returned as paths relative to projectDir.
 16→ */
 17→async function collectFiles(dir, projectDir) {
 18→  const files = [];
 19→  if (!(await fs.pathExists(dir))) return files;
 20→
 21→  const entries = await fs.readdir(dir, { withFileTypes: true });
 22→  for (const entry of entries) {
 23→    const fullPath = path.join(dir, entry.name);
 24→    if (entry.isDirectory()) {
 25→      const subFiles = await collectFiles(fullPath, projectDir);
 26→      files.push(...subFiles);
 27→    } else {
 28→      files.push(path.relative(projectDir, fullPath));
 29→    }
 30→  }
 31→  return files;
 32→}
 33→
 34→/**
 35→ * Build and write the manifest after installation.
 36→ *
 37→ * @param {string} projectDir - Project root
 38→ * @param {object} config - Install config (skfFolder, ides, etc.)
 39→ * @param {object} options - Additional info (version, ideFiles)
 40→ */
 41→async function writeManifest(projectDir, config, options = {}) {
 42→  const skfFolder = config.skfFolder || '_bmad/skf';
 43→  const skfDir = path.join(projectDir, skfFolder);
 44→  const sidecarDir = path.join(projectDir, '_bmad', '_memory', 'forger-sidecar');
 45→
 46→  // Collect all installed files
 47→  const skfFiles = await collectFiles(skfDir, projectDir);
 48→  const sidecarFiles = await collectFiles(sidecarDir, projectDir);
 49→
 50→  // Collect IDE command files
 51→  const ideFiles = options.ideFiles || [];
 52→
 53→  // Collect learning material files
 54→  const learnDir = path.join(projectDir, '_skf-learn');
 55→  const learnFiles = await collectFiles(learnDir, projectDir);
 56→
 57→  // Collect output folder gitkeep files
 58→  const outputFiles = [];
 59→  for (const folder of [config.skills_output_folder || 'skills', config.forge_data_folder || 'forge-data']) {
 60→    const gitkeep = path.join(folder, '.gitkeep');
 61→    if (await fs.pathExists(path.join(projectDir, gitkeep))) {
 62→      outputFiles.push(gitkeep);
 63→    }
 64→  }
 65→
 66→  const manifest = {
 67→    version: options.version || 'unknown',
 68→    installed_at: new Date().toISOString(),
 69→    action: config._action || 'fresh',
 70→    module: 'skf',
 71→    skf_folder: skfFolder,
 72→    ides: config.ides || [],
 73→    skills_output_folder: config.skills_output_folder || 'skills',
 74→    forge_data_folder: config.forge_data_folder || 'forge-data',
 75→    directories: [skfFolder, '_bmad/_memory/forger-sidecar', ...(learnFiles.length > 0 ? ['_skf-learn'] : [])],
 76→    files: {
 77→      skf: skfFiles,
 78→      sidecar: sidecarFiles,
 79→      ide_commands: ideFiles,
 80→      learning: learnFiles,
 81→      output: outputFiles,
 82→    },
 83→  };
 84→
 85→  const manifestDir = path.join(projectDir, MANIFEST_DIR);
 86→  await fs.ensureDir(manifestDir);
 87→
 88→  const yamlStr = yaml.dump(manifest, { lineWidth: -1, sortKeys: false });
 89→  await fs.writeFile(
 90→    path.join(manifestDir, MANIFEST_FILE),
 91→    `# SKF Installation Manifest - Generated by installer\n# Do not edit manually\n${yamlStr}`,
 92→    'utf8',
 93→  );
 94→}
 95→
 96→/**
 97→ * Read an existing manifest, or return null if none exists.
 98→ */
 99→async function readManifest(projectDir) {
100→  const manifestPath = path.join(projectDir, MANIFEST_DIR, MANIFEST_FILE);
101→  try {
102→    const content = await fs.readFile(manifestPath, 'utf8');
103→    return yaml.load(content) || null;
104→  } catch {
105→    return null;
106→  }
107→}
108→
109→module.exports = { writeManifest, readManifest, MANIFEST_DIR, MANIFEST_FILE };
110→

  1→/**
  2→ * SKF Uninstall Command
  3→ * Clean removal of SKF files, IDE commands, sidecar, and output folders.
  4→ * Uses the manifest to know exactly what to remove.
  5→ */
  6→
  7→const chalk = require('chalk');
  8→const path = require('node:path');
  9→const fs = require('fs-extra');
 10→const { confirm, isCancel, spinner, log, outro } = require('@clack/prompts');
 11→const { readManifest, MANIFEST_DIR, MANIFEST_FILE } = require('../lib/manifest');
 12→
 13→/**
 14→ * Count files that still exist on disk from manifest lists.
 15→ */
 16→async function countExistingFiles(projectDir, manifest) {
 17→  const allFiles = [
 18→    ...(manifest.files.skf || []),
 19→    ...(manifest.files.sidecar || []),
 20→    ...(manifest.files.ide_commands || []),
 21→    ...(manifest.files.learning || []),
 22→    ...(manifest.files.output || []),
 23→  ];
 24→
 25→  let existing = 0;
 26→  for (const file of allFiles) {
 27→    if (await fs.pathExists(path.join(projectDir, file))) {
 28→      existing++;
 29→    }
 30→  }
 31→  return { total: allFiles.length, existing };
 32→}
 33→
 34→/**
 35→ * Display what will be removed, grouped by category.
 36→ */
 37→async function displayRemovalPlan(projectDir, manifest) {
 38→  const categories = [
 39→    { key: 'skf', label: 'SKF module files', dir: manifest.skf_folder },
 40→    { key: 'sidecar', label: 'Agent sidecar state', dir: '_bmad/_memory/forger-sidecar' },
 41→    { key: 'ide_commands', label: 'IDE command files' },
 42→    { key: 'learning', label: 'Learning material', dir: '_skf-learn' },
 43→    { key: 'output', label: 'Output folder scaffolding' },
 44→  ];
 45→
 46→  const lines = [];
 47→  for (const cat of categories) {
 48→    const files = manifest.files[cat.key] || [];
 49→    if (files.length === 0) continue;
 50→
 51→    // Count how many still exist
 52→    let existCount = 0;
 53→    for (const f of files) {
 54→      if (await fs.pathExists(path.join(projectDir, f))) existCount++;
 55→    }
 56→
 57→    if (existCount === 0) continue;
 58→
 59→    if (cat.dir) {
 60→      lines.push(`${chalk.red('×')} ${cat.label} ${chalk.dim(`(${cat.dir}/ — ${existCount} files)`)}`);
 61→    } else {
 62→      lines.push(`${chalk.red('×')} ${cat.label} ${chalk.dim(`(${existCount} files)`)}`);
 63→    }
 64→  }
 65→
 66→  // Manifest itself
 67→  lines.push(`${chalk.red('×')} Installation manifest ${chalk.dim(`(${MANIFEST_DIR}/${MANIFEST_FILE})`)}`);
 68→
 69→  log.warn(`The following will be removed:\n${lines.join('\n')}`);
 70→}
 71→
 72→/**
 73→ * Remove files listed in the manifest, then clean empty parent directories.
 74→ */
 75→async function removeFiles(projectDir, fileList) {
 76→  let removed = 0;
 77→  for (const file of fileList) {
 78→    const fullPath = path.join(projectDir, file);
 79→    if (await fs.pathExists(fullPath)) {
 80→      await fs.remove(fullPath);
 81→      removed++;
 82→    }
 83→  }
 84→  return removed;
 85→}
 86→
 87→/**
 88→ * Remove a directory if it exists and is empty (or force remove).
 89→ */
 90→async function removeEmptyDir(dirPath) {
 91→  if (!(await fs.pathExists(dirPath))) return;
 92→  try {
 93→    const entries = await fs.readdir(dirPath);
 94→    if (entries.length === 0) {
 95→      await fs.remove(dirPath);
 96→    }
 97→  } catch {
 98→    // ignore
 99→  }
100→}
101→
102→module.exports = {
103→  command: 'uninstall',
104→  description: 'Remove SKF installation from the current project',
105→  options: [],
106→  action: async () => {
107→    try {
108→      const projectDir = process.cwd();
109→      const manifest = await readManifest(projectDir);
110→
111→      if (!manifest) {
112→        // Check if SKF exists without manifest
113→        const skfExists = await fs.pathExists(path.join(projectDir, '_bmad/skf'));
114→        if (skfExists) {
115→          log.warn(
116→            'No manifest found. Reinstall first to generate one,\nthen run uninstall again for clean removal.\nRun: npx bmad-module-skill-forge install',
117→          );
118→        } else {
119→          log.warn('SKF is not installed in this directory.');
120→        }
121→        process.exit(0);
122→        return;
123→      }
124→
125→      const { existing } = await countExistingFiles(projectDir, manifest);
126→      if (existing === 0) {
127→        log.warn('No SKF files found to remove.');
128→        // Clean up stale manifest
129→        await fs.remove(path.join(projectDir, MANIFEST_DIR, MANIFEST_FILE));
130→        process.exit(0);
131→        return;
132→      }
133→
134→      await displayRemovalPlan(projectDir, manifest);
135→
136→      const shouldProceed = await confirm({
137→        message: 'Proceed with uninstall?',
138→        initialValue: false,
139→      });
140→
141→      if (isCancel(shouldProceed) || !shouldProceed) {
142→        log.warn('Uninstall cancelled.');
143→        process.exit(0);
144→        return;
145→      }
146→
147→      const s = spinner();
148→
149→      // Remove IDE commands first (scattered across project)
150→      const ideFiles = manifest.files.ide_commands || [];
151→      if (ideFiles.length > 0) {
152→        s.start('Removing IDE commands...');
153→        const ideRemoved = await removeFiles(projectDir, ideFiles);
154→        // Clean empty IDE directories
155→        const cleanedDirs = new Set();
156→        for (const f of ideFiles) {
157→          const dir = path.dirname(f);
158→          if (!cleanedDirs.has(dir)) {
159→            cleanedDirs.add(dir);
160→            await removeEmptyDir(path.join(projectDir, dir));
161→            await removeEmptyDir(path.join(projectDir, path.dirname(dir)));
162→          }
163→        }
164→        s.stop(`Removed ${ideRemoved} IDE command files`);
165→      }
166→
167→      // Remove learning material directory
168→      const learnFiles = manifest.files.learning || [];
169→      if (learnFiles.length > 0) {
170→        s.start('Removing learning material...');
171→        const learnDir = path.join(projectDir, '_skf-learn');
172→        if (await fs.pathExists(learnDir)) {
173→          await fs.remove(learnDir);
174→        }
175→        s.stop('Learning material removed');
176→      }
177→
178→      // Remove output folder scaffolding (.gitkeep only)
179→      const outputFiles = manifest.files.output || [];
180→      if (outputFiles.length > 0) {
181→        s.start('Removing output scaffolding...');
182→        await removeFiles(projectDir, outputFiles);
183→        // Remove empty output folders
184→        for (const folder of [manifest.skills_output_folder, manifest.forge_data_folder]) {
185→          if (folder) {
186→            await removeEmptyDir(path.join(projectDir, folder));
187→          }
188→        }
189→        s.stop('Output scaffolding removed');
190→      }
191→
192→      // Remove sidecar
193→      s.start('Removing agent sidecar...');
194→      const sidecarDir = path.join(projectDir, '_bmad', '_memory', 'forger-sidecar');
195→      if (await fs.pathExists(sidecarDir)) {
196→        await fs.remove(sidecarDir);
197→      }
198→      await removeEmptyDir(path.join(projectDir, '_bmad', '_memory'));
199→      s.stop('Agent sidecar removed');
200→
201→      // Remove SKF module directory
202→      s.start('Removing SKF module...');
203→      const skfDir = path.join(projectDir, manifest.skf_folder);
204→      if (await fs.pathExists(skfDir)) {
205→        await fs.remove(skfDir);
206→      }
207→      s.stop('SKF module removed');
208→
209→      // Remove manifest
210→      const manifestPath = path.join(projectDir, MANIFEST_DIR, MANIFEST_FILE);
211→      if (await fs.pathExists(manifestPath)) {
212→        await fs.remove(manifestPath);
213→      }
214→      // Clean empty _bmad/_config/ and _bmad/ if we were the only occupant
215→      await removeEmptyDir(path.join(projectDir, MANIFEST_DIR));
216→      await removeEmptyDir(path.join(projectDir, '_bmad'));
217→
218→      outro('SKF uninstalled successfully.');
219→
220→      process.exit(0);
221→    } catch (error) {
222→      console.error(chalk.red('\nUninstall failed:'), error.message);
223→      process.exit(1);
224→    }
225→  },
226→};
