  5→
  6→const { intro, outro, text, select, multiselect, confirm, note, isCancel, cancel, log } = require('@clack/prompts');
  7→const chalk = require('chalk');
  8→const figlet = require('figlet');
  9→const path = require('node:path');
 10→const fs = require('fs-extra');
 11→const yaml = require('js-yaml');
