 13→const SKF_FOLDER = '_bmad/skf';
 14→
 15→class UI {
 16→  displayBanner() {
 17→    let banner;
 18→    try {
 19→      banner = figlet.textSync('SKF', { font: 'Standard' });
 20→    } catch {
 21→      banner = '\n  S K F';
 22→    }
 23→    const packageJson = require('../../../package.json');
 24→    intro(
 25→      `${chalk.cyan(banner)}\n${chalk.white.bold('  Skill Forge')} ${chalk.dim(`v${packageJson.version}`)}\n${chalk.dim('  AST-verified, provenance-backed agent skills from code\n  repositories, documentation, and developer discourse')}`,
 26→    );
 27→  }
 28→
 29→  async detectInstallation(projectDir) {
 30→    const hasBmadSkf = await fs.pathExists(path.join(projectDir, SKF_FOLDER));
 31→    const hasBmadDir = await fs.pathExists(path.join(projectDir, '_bmad'));
 32→
 33→    if (hasBmadSkf) {
 34→      return { type: 'existing', folder: SKF_FOLDER };
 35→    }
 36→    if (hasBmadDir) {
 37→      return { type: 'bmad-ready', folder: SKF_FOLDER };
 38→    }
