 42→  async promptInstall() {
 43→    this.displayBanner();
 44→
 45→    const projectDir = process.cwd();
 46→    const defaultProjectName = path.basename(projectDir);
 47→    const detection = await this.detectInstallation(projectDir);
 48→    const skfFolder = detection.folder;
 49→
 50→    log.info(`Target: ${chalk.cyan(projectDir)}`);
 51→
 52→    let action = 'fresh';
 53→
 54→    if (detection.type === 'existing') {
 55→      log.warn(`Found existing installation at ${chalk.white(SKF_FOLDER + '/')}`);
 56→
 57→      const choice = await select({
 58→        message: 'What would you like to do?',
 59→        options: [
 60→          { label: 'Update — Replace SKF files, keep config.yaml', value: 'update' },
 61→          { label: 'Fresh install — Remove everything and start over', value: 'fresh' },
 62→          { label: 'Cancel', value: 'cancel' },
 63→        ],
 64→      });
 65→
 66→      if (isCancel(choice) || choice === 'cancel') {
 67→        cancel('Installation cancelled.');
 68→        return { cancelled: true };
 69→      }
 70→      action = choice;
 71→    } else {
 72→      log.info(`Agents and workflows will be installed in ${chalk.white(skfFolder + '/')}`);
 73→    }
 74→
 75→    if (action === 'update') {
 76→      log.info('Existing config.yaml will be preserved.');
 77→      return {
 78→        projectDir,
 79→        skfFolder,
 80→        _detection: detection,
 81→        _action: action,
 82→        cancelled: false,
 83→      };
 84→    }
 85→
 86→    // Load saved config to pre-populate defaults on fresh reinstall
 87→    const savedConfig = await this.loadSavedConfig(projectDir, skfFolder);
 88→    if (savedConfig) {
 89→      log.info('Previous configuration detected — defaults pre-populated.');
 90→    }
 91→
 92→    const ideOptions = [
 93→      { label: 'Claude Code', value: 'claude-code' },
 94→      { label: 'Cline', value: 'cline' },
 95→      { label: 'Codex', value: 'codex' },
 96→      { label: 'Cursor', value: 'cursor' },
 97→      { label: 'GitHub Copilot', value: 'github-copilot' },
 98→      { label: 'Roo Code', value: 'roo' },
 99→      { label: 'Windsurf', value: 'windsurf' },
100→      { label: 'Other', value: 'other' },
101→    ];
102→
103→    // Pre-check IDEs: saved config takes priority, then auto-detect from directories
104→    const savedIdes = savedConfig?.ides || [];
105→    let initialIdes = [];
