113→      }
114→    }
115→
116→    // Mark initially selected IDEs
117→    for (const opt of ideOptions) {
118→      opt.initialSelected = initialIdes.includes(opt.value);
119→    }
120→
121→    // Project name
122→    const project_name = await text({
123→      message: 'Project name:',
124→      initialValue: savedConfig?.project_name || defaultProjectName,
125→    });
126→    if (isCancel(project_name)) {
127→      cancel('Installation cancelled.');
128→      return { cancelled: true };
129→    }
130→
131→    // Skills output folder
