143→      message: 'Where should forge workspace artifacts be stored?',
144→      initialValue: savedConfig?.forge_data_folder || 'forge-data',
145→    });
146→    if (isCancel(forge_data_folder)) {
147→      cancel('Installation cancelled.');
148→      return { cancelled: true };
149→    }
150→
151→    // IDE selection
