165→      message: 'Install learning & reference material?',
166→      initialValue: true,
167→    });
168→    if (isCancel(install_learning)) {
169→      cancel('Installation cancelled.');
170→      return { cancelled: true };
171→    }
172→
173→    return {
174→      projectDir,
175→      project_name,
176→      skills_output_folder,
177→      forge_data_folder,
178→      ides,
179→      install_learning,
180→      skfFolder,
181→      _detection: detection,
182→      _action: action,
183→      cancelled: false,
184→    };
