  1→/**
  2→ * IDE Command Generator - Creates IDE-specific command/skill files
  3→ * for each selected IDE so workflows and agents appear in command palettes.
  4→ */
  5→
  6→const path = require('node:path');
  7→const fs = require('fs-extra');
  8→const yaml = require('js-yaml');
  9→
 10→/**
 11→ * IDE target directory mapping.
 12→ * Maps IDE code -> relative directory where command files are written.
 13→ */
 14→const IDE_TARGETS = {
 15→  'claude-code': '.claude/commands',
 16→  cursor: '.cursor/commands',
 17→  cline: '.clinerules/workflows',
 18→  codex: '.codex/prompts',
 19→  'github-copilot': '.github/prompts',
 20→  roo: '.roo/commands',
 21→  windsurf: '.windsurf/workflows',
 22→};
 23→
 24→/**
 25→ * Generate the agent command file content.
 26→ */
 27→function renderAgentCommand(agentName, description, agentPath) {
 28→  return `---
 29→name: '${agentName}'
 30→description: '${agentName} agent'
 31→---
 32→
 33→You must fully embody this agent's persona and follow all activation instructions exactly as specified. NEVER break character until given an exit command.
 34→
 35→<agent-activation CRITICAL="TRUE">
 36→1. LOAD the FULL agent file from {project-root}/${agentPath}
 37→2. READ its entire contents - this contains the complete agent persona, menu, and instructions
 38→3. FOLLOW every step in the <activation> section precisely
 39→4. DISPLAY the welcome/greeting as instructed
 40→5. PRESENT the numbered menu
 41→6. WAIT for user input before proceeding
 42→</agent-activation>
 43→`;
 44→}
 45→
 46→/**
 47→ * Generate a workflow command file content.
 48→ */
 49→function renderWorkflowCommand(description, workflowPath) {
 50→  return `---
 51→description: '${description}'
 52→---
 53→
 54→IT IS CRITICAL THAT YOU FOLLOW THIS COMMAND: LOAD the FULL {project-root}/${workflowPath}, READ its entire contents and follow its directions exactly!
 55→`;
 56→}
 57→
 58→/**
 59→ * Collect agent artifacts from the installed SKF directory.
 60→ * Returns array of { name, description, relativePath }.
 61→ */
 62→async function collectAgents(skfDir, skfFolder) {
 63→  const agentsDir = path.join(skfDir, 'agents');
 64→  const agents = [];
 65→
 66→  if (!(await fs.pathExists(agentsDir))) return agents;
 67→
 68→  const files = await fs.readdir(agentsDir);
 69→  for (const file of files) {
 70→    // Look for compiled .md agent files (not .agent.yaml source)
 71→    if (!file.endsWith('.md')) continue;
 72→
 73→    const agentName = file.replace('.md', '');
 74→    const filePath = path.join(agentsDir, file);
 75→
 76→    // Try to extract description from the compiled markdown frontmatter
 77→    let description = `${agentName} agent`;
 78→    try {
 79→      const content = await fs.readFile(filePath, 'utf8');
 80→      const fmMatch = content.match(/^---\s*\n([\s\S]*?)\n---/);
 81→      if (fmMatch) {
 82→        const fm = yaml.load(fmMatch[1]);
 83→        if (fm && fm.title) description = fm.title;
 84→      }
 85→    } catch {
 86→      /* use default description */
 87→    }
 88→
 89→    agents.push({
 90→      name: agentName,
 91→      description,
 92→      relativePath: `${skfFolder}/agents/${file}`,
 93→    });
 94→  }
 95→
 96→  return agents;
 97→}
 98→
 99→/**
100→ * Collect workflow artifacts from the installed SKF directory.
101→ * Returns array of { name, description, relativePath }.
102→ */
103→async function collectWorkflows(skfDir, skfFolder) {
104→  const workflowsDir = path.join(skfDir, 'workflows');
105→  const workflows = [];
106→
107→  if (!(await fs.pathExists(workflowsDir))) return workflows;
108→
109→  // Recursively find workflow.md files
110→  const walkDir = async (dir, relBase) => {
111→    const entries = await fs.readdir(dir, { withFileTypes: true });
112→    for (const entry of entries) {
113→      if (entry.isDirectory()) {
114→        await walkDir(path.join(dir, entry.name), `${relBase}/${entry.name}`);
115→      } else if (entry.name === 'workflow.md') {
116→        const filePath = path.join(dir, entry.name);
117→        const workflowName = path.basename(path.dirname(filePath));
118→
119→        // Extract description from frontmatter
120→        let description = workflowName;
121→        try {
122→          const content = await fs.readFile(filePath, 'utf8');
123→          const fmMatch = content.match(/^---\s*\n([\s\S]*?)\n---/);
124→          if (fmMatch) {
125→            const fm = yaml.load(fmMatch[1]);
126→            if (fm && fm.description) description = fm.description;
127→          }
128→        } catch {
129→          /* use default */
130→        }
131→
132→        workflows.push({
133→          name: workflowName,
134→          description,
135→          relativePath: `${skfFolder}/workflows${relBase}/workflow.md`,
136→        });
137→      }
138→    }
139→  };
140→
141→  await walkDir(workflowsDir, '');
142→  return workflows;
143→}
144→
145→/**
146→ * Remove SKF-related command files from an IDE target directory.
147→ * Only removes files matching the bmad-skf-* and bmad-agent-skf-* patterns.
148→ */
149→async function cleanSkfCommands(targetDir) {
150→  if (!(await fs.pathExists(targetDir))) return 0;
151→
152→  const files = await fs.readdir(targetDir);
153→  let removed = 0;
154→  for (const file of files) {
155→    if (file.startsWith('bmad-skf-') || file.startsWith('bmad-agent-skf-')) {
156→      await fs.remove(path.join(targetDir, file));
157→      removed++;
158→    }
159→  }
160→
161→  // Remove empty parent directories (e.g. .cursor/commands/ then .cursor/)
162→  if (removed > 0) {
163→    const remaining = await fs.readdir(targetDir);
164→    if (remaining.length === 0) {
165→      await fs.remove(targetDir);
166→      const parentDir = path.dirname(targetDir);
167→      const parentRemaining = await fs.readdir(parentDir);
168→      if (parentRemaining.length === 0) {
169→        await fs.remove(parentDir);
170→      }
171→    }
172→  }
173→
174→  return removed;
175→}
176→
177→/**
178→ * Remove stale SKF command files from all known IDE directories.
179→ * Called before generating new commands to handle IDE selection changes.
180→ */
181→async function cleanAllSkfCommands(projectDir) {
182→  for (const targetRelDir of Object.values(IDE_TARGETS)) {
183→    const targetDir = path.join(projectDir, targetRelDir);
184→    await cleanSkfCommands(targetDir);
185→  }
186→}
187→
188→/**
189→ * Generate IDE command files for all selected IDEs.
190→ *
191→ * @param {string} projectDir - Project root directory
192→ * @param {string} skfFolder - Relative path to SKF dir (e.g. '_bmad/skf')
193→ * @param {string[]} ides - Array of IDE codes (e.g. ['claude-code', 'cursor'])
194→ * @returns {{ generated: number, ides: string[] }}
195→ */
196→async function generateIdeCommands(projectDir, skfFolder, ides) {
197→  // Always clean old SKF commands from all IDEs first
198→  await cleanAllSkfCommands(projectDir);
199→
200→  if (!ides || ides.length === 0) return { generated: 0, ides: [] };
201→
202→  const skfDir = path.join(projectDir, skfFolder);
203→  const moduleCode = 'skf';
204→
205→  // Collect artifacts
206→  const agents = await collectAgents(skfDir, skfFolder);
207→  const workflows = await collectWorkflows(skfDir, skfFolder);
208→
209→  let totalGenerated = 0;
210→  const processedIdes = [];
211→  const generatedFiles = [];
212→
213→  for (const ide of ides) {
214→    const targetRelDir = IDE_TARGETS[ide];
215→    if (!targetRelDir) continue; // Skip unknown IDEs (e.g. 'other')
216→
217→    const targetDir = path.join(projectDir, targetRelDir);
218→    await fs.ensureDir(targetDir);
219→
220→    // Generate agent commands
221→    for (const agent of agents) {
222→      const fileName = `bmad-agent-${moduleCode}-${agent.name}.md`;
223→      const content = renderAgentCommand(agent.name, agent.description, agent.relativePath);
224→      await fs.writeFile(path.join(targetDir, fileName), content, 'utf8');
225→      totalGenerated++;
226→      generatedFiles.push(`${targetRelDir}/${fileName}`);
227→    }
228→
229→    // Generate workflow commands
230→    for (const workflow of workflows) {
231→      const fileName = `bmad-${moduleCode}-${workflow.name}.md`;
232→      const content = renderWorkflowCommand(workflow.description, workflow.relativePath);
233→      await fs.writeFile(path.join(targetDir, fileName), content, 'utf8');
234→      totalGenerated++;
235→      generatedFiles.push(`${targetRelDir}/${fileName}`);
236→    }
237→
238→    processedIdes.push(ide);
239→  }
240→
241→  return { generated: totalGenerated, ides: processedIdes, files: generatedFiles };
242→}
243→
244→module.exports = { generateIdeCommands };
