 14→const path = require('node:path');
 15→const os = require('node:os');
 16→const fs = require('fs-extra');
 17→const yaml = require('js-yaml');
 18→
 19→// ANSI colors
 20→const colors = {
 21→  reset: '\u001B[0m',
 22→  green: '\u001B[32m',
 23→  red: '\u001B[31m',
 24→  yellow: '\u001B[33m',
 25→  cyan: '\u001B[36m',
 26→  dim: '\u001B[2m',
 27→};
 28→
 29→let passed = 0;
 30→let failed = 0;
 31→
 32→function assert(condition, testName, errorMessage = '') {
 33→  if (condition) {
 34→    console.log(`${colors.green}✓${colors.reset} ${testName}`);
 35→    passed++;
 36→  } else {
 37→    console.log(`${colors.red}✗${colors.reset} ${testName}`);
 38→    if (errorMessage) {
 39→      console.log(`  ${colors.dim}${errorMessage}${colors.reset}`);
 40→    }
 41→    failed++;
 42→  }
 43→}
