 45→/**
 46→ * Create a temp directory for a test case.
 47→ */
 48→async function makeTempDir(label) {
 49→  const dir = path.join(os.tmpdir(), `skf-test-${label}-${Date.now()}`);
 50→  await fs.ensureDir(dir);
 51→  return dir;
 52→}
 53→
 54→/**
 55→ * Suppress ora spinners, console.log, and stderr writes during install to keep test output clean.
 56→ */
 57→function suppressConsole() {
 58→  const origLog = console.log;
 59→  const origStdoutWrite = process.stdout.write;
 60→  const origStderrWrite = process.stderr.write;
 61→  console.log = () => {};
 62→  process.stdout.write = () => true;
 63→  process.stderr.write = () => true;
 64→  return () => {
 65→    console.log = origLog;
 66→    process.stdout.write = origStdoutWrite;
 67→    process.stderr.write = origStderrWrite;
 68→  };
 69→}
