132→
133→    // Verify manifest
134→    const manifestPath = path.join(projectDir, '_bmad/_config/skf-manifest.yaml');
135→    assert(await fs.pathExists(manifestPath), 'manifest created');
136→    const manifest = yaml.load(await fs.readFile(manifestPath, 'utf8'));
137→    assert(manifest.module === 'skf', 'manifest has module: skf');
138→    assert(manifest.action === 'fresh', 'manifest has action: fresh');
139→    assert(Array.isArray(manifest.files.skf) && manifest.files.skf.length > 0, 'manifest tracks SKF files');
